// lib/node_modules/websocketd/daemon.js
const { exec } = require('child_process')
const { WebSocketServer } = require('ws')
const path = require('path')

const envPath = path.join(__dirname, '../../../env.json')
try {
  process.env = require(envPath)
} catch (e) {
  console.error(`Failed to load env.json. Looked at: ${envPath}`, e.message)
  process.env = { PORT: '8080' } 
}
console.log('env:', process.env)


const WS_PORT = process.env.WS_PORT || 8080
const BITCOIN_RPCPORT = process.env.BITCOIN_RPCPORT || 18443
const BITCOIN_RPCUSER = process.env.BITCOIN_RPCUSER || 'rpcuser'
const BITCOIN_RPCPASSWORD = process.env.BITCOIN_RPCPASSWORD || 'rpcpassword'
const NETWORK = process.env.BITCOIN_NETWORK || 'regtest'


const {
  LIGHTNING_DIR_4,
  LIGHTNING_DIR_5,
  LIGHTNING_DIR_6,
  BITCOIN_CLI_BIN,
  LIGHTNING_CLI_BIN
} = process.env


const BITCOIN_CLI = BITCOIN_CLI_BIN || '/usr/local/bin/bitcoin-cli'
const LIGHTNING_CLI = LIGHTNING_CLI_BIN || '/usr/local/bin/lightning-cli'

const LIGHTNING_DIRS = {
  'node4': LIGHTNING_DIR_4 || '/Users/a1707/lightning4',
  'node5': LIGHTNING_DIR_5 || '/Users/a1707/lightning5',
  'node6': LIGHTNING_DIR_6 || '/Users/a1707/lightning6'
}

// -----------------------------------------------------------------------------
// 🧰 Helpers
// -----------------------------------------------------------------------------
function runCommand (cmd, opts = {}) {
  return new Promise((resolve, reject) => {
    exec(cmd, { maxBuffer: 10 * 1024 * 1024, ...opts }, (err, stdout, stderr) => {
      if (err) return reject(new Error(stderr || err.message))
      resolve({ stdout: stdout.toString(), stderr: stderr.toString() })
    })
  })
}

function btcRpc (method, params = []) {
  const cmd = `${BITCOIN_CLI} -regtest -rpcuser=${BITCOIN_RPCUSER} -rpcpassword=${BITCOIN_RPCPASSWORD} -rpcport=${BITCOIN_RPCPORT} ${method} ${params.join(' ')}`
  return runCommand(cmd)
}

function lnRpc (nodeId, method, params = []) {
  const dir = LIGHTNING_DIRS[nodeId]
  if (!dir) return Promise.reject(new Error(`Unknown node ID: ${nodeId}`))

  const cmd = `${LIGHTNING_CLI} --network=${NETWORK} --lightning-dir=${dir} ${method} ${params.join(' ')}`
  return runCommand(cmd)
}

// -----------------------------------------------------------------------------
// ⚡ Core Lightning functions
// -----------------------------------------------------------------------------
async function lightning_getinfo (data = {}) {
  const nodeId = data.nodeId || 'node4'
  try {
    const { stdout } = await lnRpc(nodeId, 'getinfo')
    const parsed = JSON.parse(stdout)
    return { status: 'success', data: parsed }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function lightning_listfunds_raw (data = {}) {
  const nodeId = data.nodeId || 'node4'
  try {
    const { stdout } = await lnRpc(nodeId, 'listfunds')
    const parsed = JSON.parse(stdout)
    return { status: 'success', data: parsed }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

// -----------------------------------------------------------------------------
// ₿ Core Bitcoin functions
// -----------------------------------------------------------------------------
async function bitcoin_newaddress () {
  try {
    const { stdout } = await btcRpc('getnewaddress')
    return { status: 'success', data: stdout.trim() }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_btc_balance () {
  try {
    const { stdout } = await btcRpc('getbalance')
    return { status: 'success', data: { btc: parseFloat(stdout.trim()) } }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


async function get_ln_balance (data = {}) {
  const nodeId = data.userId || 'node4' // Use userId as the nodeId
  try {
    const { stdout } = await lnRpc(nodeId, 'listfunds')
    const parsed = JSON.parse(stdout)
    const outputs = parsed.outputs || []

    const onchain_msat = outputs
      .filter(o => o.status === 'confirmed')
      .reduce((acc, o) => acc + (o.amount_msat || 0), 0)

    const channel_msat = (parsed.channels || [])
      .reduce((acc, c) => acc + (c.our_amount_msat|| 0), 0)
    
    const total_msat = onchain_msat + channel_msat
    const total_sats = total_msat / 1000

    return {
      status: 'success',
      data: {
        sats: total_sats,
        btc: total_sats / 1e8,
        raw: parsed 
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function sync_wallet_balances (data = {}) {
  const nodeId = data.userId || 'node4'
  try {
    // Run in parallel
    const [btcResult, lnResult] = await Promise.all([
      get_btc_balance(), // btc balance isn't user-specific in this setup
      get_ln_balance({ userId: nodeId })
    ])

    if (btcResult.status === 'error' || lnResult.status === 'error') {
      throw new Error(`BTC Error: ${btcResult.error} || LN Error: ${lnResult.error}`)
    }

    return {
      status: 'success',
      data: {
        btc_balance: btcResult.data.btc,
        ln_balance_sats: lnResult.data.sats
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_tx_details_from_btcnode (data = {}) {
  const tx_id = data.tx_id
  if (!tx_id) return { status: 'error', error: 'tx_id is required' }

  try {
    const { stdout } = await btcRpc('gettransaction', [tx_id])
    return { status: 'success', data: JSON.parse(stdout) }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


async function get_tx_details_from_lnnode (data = {}) {
  const payment_hash = data.payment_hash
  const nodeId = data.userId || 'node4'
  if (!payment_hash) return { status: 'error', error: 'payment_hash is required' }

  try {
    const params = [`payment_hash=${payment_hash}`]
    const { stdout } = await lnRpc(nodeId, 'listinvoices', params)
    
    const parsed = JSON.parse(stdout)
    
    if (!parsed.invoices || parsed.invoices.length === 0) {
      return { status: 'error', error: 'Invoice not found' }
    }
    
    return { status: 'success', data: parsed.invoices[0] }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


async function list_btc_transactions (data = {}) {
 
  const count = data.count || 20 
  const skip = data.skip || 0
  
  try {
    const { stdout } = await btcRpc('listtransactions', ['"*"', count, skip])
    const parsed = JSON.parse(stdout)
    // Reverse to show newest first
    return { status: 'success', data: parsed.reverse() }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


async function list_ln_invoices (data = {}) {
  const nodeId = data.userId || 'node4'
  
  try {
    const { stdout } = await lnRpc(nodeId, 'listinvoices')
    const parsed = JSON.parse(stdout)
     // Reverse to show newest first
    return { status: 'success', data: parsed.invoices.reverse() }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function estimate_btc_fee (data = {}) {
  const priority = data.priority || 'medium'
  const blockTargets = {
    'high': 2,
    'medium': 6,
    'low': 100
  }
  const target = blockTargets[priority] || 6

  try {
    const { stdout } = await btcRpc('estimatesmartfee', [target])
    const parsed = JSON.parse(stdout)
    return { 
      status: 'success', 
      data: { 
        feerate_btc_per_kb: parsed.feerate || 'unknown',
        blocks: parsed.blocks || target
      } 
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function convert_btc_to_usd (data = {}) {
  const amount_btc = data.amount_btc
  if (amount_btc === undefined) {
    return { status: 'error', error: 'amount_btc is required' }
  }

  // Using CoinGecko's free API
  const url = 'https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd'

  try {
    const response = await fetch(url)
    
    if (!response.ok) {
      throw new Error(`API request failed with status ${response.status}`)
    }

    const parsed = await response.json()

    // CoinGecko's response format is { "bitcoin": { "usd": 65000.12 } }
    if (!parsed.bitcoin || !parsed.bitcoin.usd) {
      throw new Error('Failed to parse price from API response')
    }

    const rate = parseFloat(parsed.bitcoin.usd)
    const usd_value = rate * amount_btc
    
    return {
      status: 'success',
      data: {
        btc_amount: amount_btc,
        usd_value: usd_value,
        rate_per_btc: rate
      }
    }
  } catch (e) {
    return { status: 'error', error: `Price API request failed: ${e.message}` }
  }
}

// -----------------------------------------------------------------------------
// 🔄 WebSocket handler
// -----------------------------------------------------------------------------
async function handleMessage (msg, ws, server) {
  const [by, to, mid] = msg.head || []
  const intent = msg.type
  const data = msg.data 

  console.log(`📩 Received from ${by}:`, intent, data || '')

  if (intent === 'daemon-stop') {
    console.log('🚨 Stopping backend daemon as requested...')
    // Handle graceful shutdown if needed
  }

  // UPDATED: Added all new Stage 1 functions
  const actions = {
    // Core functions 
    'lightning-getinfo': lightning_getinfo,
    'lightning-listfunds': lightning_listfunds_raw, 
    'bitcoin-newaddress': bitcoin_newaddress,
    
    // Stage 1 functions 
    'get_btc_balance': get_btc_balance,
    'get_ln_balance': get_ln_balance,
    'sync_wallet_balances': sync_wallet_balances,
    'convert_btc_to_usd': convert_btc_to_usd,
    'estimate_btc_fee': estimate_btc_fee,
    'get_tx_details_from_btcnode': get_tx_details_from_btcnode,
    'get_tx_details_from_lnnode': get_tx_details_from_lnnode,
    'list_btc_transactions': list_btc_transactions,
    'list_ln_invoices': list_ln_invoices
  }

  const fn = actions[intent]
  if (!fn) {
    // NEW: Handle unknown actions gracefully
    return ws.send(JSON.stringify({
      head: ['backend', by, mid],
      type: `${intent}:response`,
      data: { status: 'error', error: `Unknown action: ${intent}` }
    }))
  }

  // Pass the 'data' payload to the action function
  const payload = await fn(data) 
  
  // Send the response
  ws.send(JSON.stringify({
    head: ['backend', by, mid],
    type: `${intent}:response`,
    data: payload
  }))
}

// -----------------------------------------------------------------------------
// 🚀 WebSocket server setup
// -----------------------------------------------------------------------------
const wss = a = new WebSocketServer({ port: Number(WS_PORT) })
console.log(`🚀 Backend daemon listening on ws://localhost:${WS_PORT}`)

wss.on('connection', (ws, req) => {
  console.log('client connected:', req.socket.remoteAddress)
  ws.on('message', async (raw) => {
    try {
      const msg = JSON.parse(raw.toString())
      await handleMessage(msg, ws, wss)
    } catch (err) {
      console.error('Message error:', err.message)
      ws.send(JSON.stringify({ type: 'error', data: { error: err.message } }))
    }
  })
  ws.on('close', () => console.log('client disconnected'))
})